import React, { useState, useEffect } from 'react';
import Navbar from '../../components/common/Navbar';
import Sidebar from '../../components/common/Sidebar';
import Card from '../../components/common/Card';
import LineChart from '../../components/charts/LineChart';
import BarChart from '../../components/charts/BarChart';
import Loader from '../../components/common/Loader';
import { getStudentDashboard } from '../../services/api';

const StudentDashboard = () => {
  const userName = localStorage.getItem('userName') || 'Student';
  const userId = localStorage.getItem('userId');
  const [loading, setLoading] = useState(true);
  const [dashboardData, setDashboardData] = useState(null);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await getStudentDashboard(userId);
      setDashboardData(response.data);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      setDashboardData(null);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen galaxy-bg">
        <Navbar role="Student" userName={userName} />
        <div className="flex">
          <Sidebar role="student" />
          <main className="flex-1">
            <Loader />
          </main>
        </div>
      </div>
    );
  }

  const accuracyData = {
    labels: dashboardData?.accuracyTrend?.labels || [],
    datasets: [{
      label: 'Accuracy %',
      data: dashboardData?.accuracyTrend?.data || [],
      borderColor: 'rgb(139, 92, 246)',
      backgroundColor: 'rgba(139, 92, 246, 0.5)',
    }],
  };

  const topicData = {
    labels: dashboardData?.topicPerformance?.labels || [],
    datasets: [{
      label: 'Score %',
      data: dashboardData?.topicPerformance?.data || [],
      backgroundColor: ['#8b5cf6', '#3b82f6', '#10b981', '#f59e0b', '#ef4444'],
    }],
  };

  if (!dashboardData) {
    return (
      <div className="min-h-screen galaxy-bg">
        <Navbar role="Student" userName={userName} />
        <div className="flex">
          <Sidebar role="student" />
          <main className="flex-1 p-6">
            <div className="glass-card rounded-xl p-8 text-center">
              <p className="text-white text-xl">Unable to load dashboard data. Please ensure backend is running.</p>
            </div>
          </main>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen galaxy-bg">
      <Navbar role="Student" userName={userName} />
      <div className="flex">
        <Sidebar role="student" />
        <main className="flex-1 p-6">
          <h2 className="text-3xl font-bold text-white mb-6">Welcome, {userName}! 🎓</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-6">
            <Card 
              title="Total Quizzes" 
              value={dashboardData.totalQuizzes} 
              icon="📝" 
              color="blue" 
            />
            <Card 
              title="Average Accuracy" 
              value={`${dashboardData.avgAccuracy}%`} 
              icon="🎯" 
              color="green" 
            />
            <Card 
              title="Avg Solving Time" 
              value={dashboardData.avgTime} 
              icon="⏱️" 
              color="yellow" 
            />
            <Card 
              title="Weak Topic" 
              value={dashboardData.weakTopic} 
              icon="📚" 
              color="red" 
            />
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
            <div className="glass-card rounded-xl shadow-lg p-6">
              <LineChart data={accuracyData} title="Accuracy Trend (Last 7 Days)" />
            </div>
            <div className="glass-card rounded-xl shadow-lg p-6">
              <BarChart data={topicData} title="Topic Performance" />
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="glass-card rounded-xl shadow-lg p-6">
              <h3 className="text-xl font-semibold mb-4 text-white">Recent Quiz Activity</h3>
              <div className="space-y-3">
                {dashboardData.recentActivity?.length > 0 ? (
                  dashboardData.recentActivity.map((activity, index) => (
                    <div key={index} className="flex justify-between items-center border-b border-gray-600 pb-2">
                      <div>
                        <p className="font-semibold text-white">{activity.quiz}</p>
                        <p className="text-sm text-gray-400">{activity.date}</p>
                      </div>
                      <div className="text-right">
                        <p className="font-semibold text-purple-400">{activity.score}</p>
                        <p className="text-sm text-gray-400">{activity.time}</p>
                      </div>
                    </div>
                  ))
                ) : (
                  <p className="text-gray-400 text-center py-4">No recent activity</p>
                )}
              </div>
            </div>

            <div className="glass-card rounded-xl shadow-lg p-6">
              <h3 className="text-xl font-semibold mb-4 text-white">Recommendations</h3>
              <div className="space-y-3">
                {dashboardData.recommendations?.length > 0 ? (
                  dashboardData.recommendations.map((rec, index) => (
                    <div key={index} className={`bg-gradient-to-r ${rec.color} bg-opacity-20 border-l-4 border-${rec.borderColor} p-3 rounded`}>
                      <p className="font-semibold text-white">{rec.title}</p>
                      <p className="text-sm text-gray-300">{rec.description}</p>
                    </div>
                  ))
                ) : (
                  <p className="text-gray-400 text-center py-4">No recommendations yet</p>
                )}
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default StudentDashboard;
